class Solution {
public:
    bool isSubstringPresent(string s) {
        string rev = s;
        reverse(rev.begin(), rev.end());
        for (int i = 0; i <= s.length() - 2; i++) {
            string substr = s.substr(i, 2);
            if (rev.find(substr) != string::npos) {
                return true;
            }
        }
        return false;
    }
};
